-- Source for visual media candidates: public Wger exercise search API
-- This file overwrites existing visual_guide_url, description_ko, description_en values.
BEGIN;

-- 벤치 프레스 <- Bench Press (query: Bench Press)
UPDATE exercises
SET
  visual_guide_url = 'https://wger.de/media/exercise-images/192/Bench-press-1.png',
  overview_ko = '벤치 프레스는 가슴, 전면 어깨, 삼두 중심의 미는 동작 계열 운동입니다. 상체 전면의 힘을 키우고 중량을 다루는 기본기를 만드는 데 유용합니다.',
  overview_en = 'Bench Press is a pressing exercise for the chest, front delts, and triceps. It is a key pattern for developing upper-body strength, pressing mechanics, and front-side muscular development.',
  why_ko = '가슴, 어깨, 삼두의 근력과 근비대를 함께 노릴 수 있고, 다른 프레스 계열 운동의 기반이 되는 패턴이라 프로그램 구성 가치가 높습니다.',
  why_en = 'A strong press supports hypertrophy of the chest, shoulders, and triceps while also improving performance in many other upper-body training movements.',
  how_ko = '견갑을 안정적으로 고정하고 손목, 팔꿈치, 어깨 라인을 편안하게 맞춥니다.
내려가는 구간은 천천히 통제하고 목표 지점에서 반동 없이 멈춥니다.
지면이나 벤치에 힘을 전달하며 밀어 올리고, 마무리에서도 어깨 위치를 무너지지 않게 유지합니다.',
  how_en = 'Create a stable shoulder position and line up the wrists, elbows, and pressing path.
Control the lowering phase without losing tension or bouncing out of the bottom.
Press smoothly while keeping the shoulders organized and the torso stable.',
  description_ko = '개요
벤치 프레스는 가슴, 전면 어깨, 삼두 중심의 미는 동작 계열 운동입니다. 상체 전면의 힘을 키우고 중량을 다루는 기본기를 만드는 데 유용합니다.

왜 하나요?
가슴, 어깨, 삼두의 근력과 근비대를 함께 노릴 수 있고, 다른 프레스 계열 운동의 기반이 되는 패턴이라 프로그램 구성 가치가 높습니다.

수행 방법
1. 견갑을 안정적으로 고정하고 손목, 팔꿈치, 어깨 라인을 편안하게 맞춥니다.
2. 내려가는 구간은 천천히 통제하고 목표 지점에서 반동 없이 멈춥니다.
3. 지면이나 벤치에 힘을 전달하며 밀어 올리고, 마무리에서도 어깨 위치를 무너지지 않게 유지합니다.',
  description_en = 'Overview
Bench Press is a pressing exercise for the chest, front delts, and triceps. It is a key pattern for developing upper-body strength, pressing mechanics, and front-side muscular development.

Why do this exercise?
A strong press supports hypertrophy of the chest, shoulders, and triceps while also improving performance in many other upper-body training movements.

How to do it
1. Create a stable shoulder position and line up the wrists, elbows, and pressing path.
2. Control the lowering phase without losing tension or bouncing out of the bottom.
3. Press smoothly while keeping the shoulders organized and the torso stable.'
WHERE name_ko = '벤치 프레스' AND is_custom = false;

