-- 컨벤셔널 데드리프트 <- Deadlifts (query: Conventional Deadlift)
UPDATE exercises
SET
  visual_guide_url = 'https://wger.de/media/exercise-images/184/1709c405-620a-4d07-9658-fade2b66a2df.jpeg',
  overview_ko = '컨벤셔널 데드리프트는 광배, 등 상부, 후면 어깨, 이두 중심의 힙 힌지 패턴 운동입니다. 엉덩이와 햄스트링을 적극적으로 사용하면서 전신의 힘 전달 능력을 키워줍니다.',
  overview_en = 'Conventional Deadlift is a hip-hinge exercise that trains the lats, upper back, rear delts, and biceps. It teaches powerful extension through the hips while reinforcing trunk stability and efficient force transfer.',
  why_ko = '후면 사슬을 강하게 만들어 무게를 들어 올리는 능력, 점프와 달리기 같은 폭발적인 움직임, 허리와 골반의 안정성 향상에 도움이 됩니다.',
  why_en = 'This pattern is excellent for developing posterior-chain strength, improving athletic power, and building resilience in movements that involve lifting, hinging, and accelerating.',
  how_ko = '발과 도구의 거리를 맞추고 코어를 단단히 조여 척추 중립을 유지합니다.
허리를 꺾지 말고 엉덩이를 뒤로 접으며 내려가 목표 위치를 잡습니다.
발로 지면을 밀고 엉덩이를 앞으로 보내며 올라오되 상체와 바가 몸에서 멀어지지 않게 합니다.',
  how_en = 'Set the bar or implement close to the body and brace your core first.
Hinge from the hips instead of rounding or overextending the lower back.
Drive the floor away and finish each rep with the hips and trunk arriving together.',
  description_ko = '개요
컨벤셔널 데드리프트는 광배, 등 상부, 후면 어깨, 이두 중심의 힙 힌지 패턴 운동입니다. 엉덩이와 햄스트링을 적극적으로 사용하면서 전신의 힘 전달 능력을 키워줍니다.

왜 하나요?
후면 사슬을 강하게 만들어 무게를 들어 올리는 능력, 점프와 달리기 같은 폭발적인 움직임, 허리와 골반의 안정성 향상에 도움이 됩니다.

수행 방법
1. 발과 도구의 거리를 맞추고 코어를 단단히 조여 척추 중립을 유지합니다.
2. 허리를 꺾지 말고 엉덩이를 뒤로 접으며 내려가 목표 위치를 잡습니다.
3. 발로 지면을 밀고 엉덩이를 앞으로 보내며 올라오되 상체와 바가 몸에서 멀어지지 않게 합니다.',
  description_en = 'Overview
Conventional Deadlift is a hip-hinge exercise that trains the lats, upper back, rear delts, and biceps. It teaches powerful extension through the hips while reinforcing trunk stability and efficient force transfer.

Why do this exercise?
This pattern is excellent for developing posterior-chain strength, improving athletic power, and building resilience in movements that involve lifting, hinging, and accelerating.

How to do it
1. Set the bar or implement close to the body and brace your core first.
2. Hinge from the hips instead of rounding or overextending the lower back.
3. Drive the floor away and finish each rep with the hips and trunk arriving together.'
WHERE name_ko = '컨벤셔널 데드리프트' AND is_custom = false;

